import Prism from 'https://cdn.jsdelivr.net/npm/prismjs@1/+esm';
Prism.manual = true;  // 抑制 import 时自动 highlightAll(rAF)
const link = document.createElement('link'); link.rel = 'stylesheet'; link.href = 'https://cdn.jsdelivr.net/npm/prismjs@1/themes/prism.css'; document.head.appendChild(link);
const pre = document.createElement('pre'); const code = document.createElement('code'); const lang = data.language ?? 'javascript';
code.className = `language-${lang}`; code.innerHTML = Prism.highlight(data.code, Prism.languages[lang], lang); pre.appendChild(code);
document.getElementById('code').replaceChildren(pre);

