// Fibonacci sequence generator
function fib(n) {
  const seq = [0, 1];
  for (let i = 2; i < n; i++) {
    seq.push(seq[i - 1] + seq[i - 2]);
  }
  return seq;
}

const msg = `First 10: ${fib(10).join(', ')}`;
console.log(msg);
